import React, { useState, useEffect, useRef } from "react";
import PropTypes from "prop-types";
import Filters from "./finder__filters";
import Reset from "../filters/finder__reset";
import * as createFocusTrap from "focus-trap";
import type { FiltersMobiles } from "../../types/filters/filters";

import { enableBodyScroll, disableBodyScroll } from "../../util";

/**
 * Render the mobile version of the filters.
 */
function Finder__FiltersMobile(props: FiltersMobiles) {
  const [display, setDisplay] = useState(false);
  const [focusTrap, setFocusTrap] = useState<createFocusTrap.FocusTrap | null>(
    null,
  );
  const filtersRef = useRef<HTMLDivElement | null>(null);

  // Set up the focus trap once after mount
  useEffect(() => {
    const filtersEl = filtersRef.current;
    if (!filtersEl) return;

    const trap = createFocusTrap.createFocusTrap(filtersEl, {
      initialFocus: filtersEl.querySelector(
        ".wrapper--v26-finder__filters--mobile__apply",
      ) as HTMLElement | undefined,
      onDeactivate: () => setDisplay(false),
      clickOutsideDeactivates: true,
    });

    setFocusTrap(trap);
  }, []);

  // Manage focus trap and scroll behavior based on `display`
  useEffect(() => {
    if (!focusTrap) return;

    if (display) {
      if (!focusTrap.active) focusTrap.activate();
      disableBodyScroll();
    } else {
      if (focusTrap.active) focusTrap.deactivate();
      enableBodyScroll();
    }
  }, [display, focusTrap]);

  const totalMatching =
    props.response &&
    props.response.summary &&
    props.response.summary.totalMatching;

  const noFacetsSelected =
    !props.query?.facets || Object.keys(props.query.facets).length === 0;

  // const result =
  //   totalMatching === 1 && props.summariseAs
  //     ? props.summariseAs.singular
  //     : props.summariseAs && props.summariseAs.plural
  //       ? props.summariseAs.plural
  //       : null;

  const totalMatchingMessage = totalMatching
    ? `View results (${totalMatching})`
    : "View results"; //Temporarily Left the conditional statement in incase logic of showing Close is reinstated.

  const filtersCount = props.config.displaySort ? (
    props.config.sort[0].type !== props.query.sortType ||
    Object.keys(props.query.facets).length > 0 ? (
      <span>
        Show Filters{" "}
        <span className="wrapper--v26-finder__filters--mobile__toggle__count">
          (
          {props.config.sort[0].type !== props.query.sortType
            ? Object.keys(props.query.facets).length + 1
            : Object.keys(props.query.facets).length}
          )
        </span>
      </span>
    ) : (
      <span>Filter</span>
    )
  ) : Object.keys(props.query.facets).length > 0 ? (
    <span>
      Show Filters{" "}
      <span className="wrapper--v26-finder__filters--mobile__toggle__count">
        (
        {props.config.sort[0].type !== props.query.sortType
          ? Object.keys(props.query.facets).length + 1
          : Object.keys(props.query.facets).length}
        )
      </span>
    </span>
  ) : (
    <span>Show Filter</span>
  );

  const toggle = display ? null : (
    <button
      type="button"
      className="wrapper--v26-finder__filters--mobile__toggle"
      aria-haspopup={true}
      aria-expanded={display}
      onClick={() => setDisplay(true)}
      data-filters-applied={
        Object.keys(props.query.facets).length !== 0 ||
        (props.config.displaySort &&
          props.config.sort[0].type !== props.query.sortType)
      }
    >
      <span>
        <span className="far fa-sharp fa-sliders-h icon" aria-hidden="true" />{" "}
        {filtersCount}
      </span>
    </button>
  );

  return (
    <div
      className="wrapper--v26-finder__filters"
      data-open={display}
      ref={filtersRef}
    >
      {display && (
      <button
        type="button"
        className="wrapper--v26-finder__filters--mobile__filters__close"
        aria-label="Close filters"
        onClick={() => setDisplay(false)}
      >
        <span className="far fa-times icon" aria-hidden="true"></span>
      </button>
      )}

      <div className="wrapper--v26-finder__filters__header">
        {toggle}
        {!noFacetsSelected && (
          <Reset
            clear={props.clear}
            resetSort={false}
            matrixState={props.matrixState}
            label="Clear all filters"
            site={props.config.site || "city"}
          />
        )}
      </div>
      <div className="wrapper--v26-finder__filters--mobile__filters">
        <div className="wrapper--v26-finder__filters--mobile__filters__content">
          <Filters
            config={props.config}
            query={props.query}
            response={props.response}
            update={props.update}
            clear={props.clear}
            mobile={props.mobile}
            hasMounted={props.hasMounted}
            matrixState={props.matrixState}
            updating={props.updating}
          />
        </div>
      </div>
      <div className="wrapper--v26-finder__filters__footer">
        <Reset
            clear={props.clear}
            className="v26-finder__btn_alt"
            resetSort={false}
            matrixState={props.matrixState}
            disabled={noFacetsSelected}
            label="Clear filters"
            site={props.config.site || "city"} // Ensure site is defined
          />
        <div className="wrapper--v26-finder__filters--mobile__apply">
          <button
            className="v26-finder__btn"
            type="button"
            aria-expanded={display}
            onClick={() => setDisplay(false)}
            disabled={props.updating || noFacetsSelected}
          >
            {Object.keys(props.query.facets).length === 0 ? null : (
              <span className="fa fa-chevron-left icon"></span>
            )}

            <span aria-live="polite">
              {props.updating ? (
                <>
                  <span
                    className="fas fa-spinner fa-pulse icon"
                    aria-hidden="true"
                  />{" "}
                  <span className="wrapper--v26-finder__filters--mobile__apply__text">
                    Updating {props.summariseAs && props.summariseAs.plural}…
                  </span>
                </>
              ) : (
                <span className="wrapper--finder__filters--mobile__apply__text">
                  {Object.keys(props.query.facets).length === 0
                    ? "View results" //Temporarily Left the conditional statement in incase logic of showing Close is reinstated.
                    : totalMatchingMessage}
                </span>
              )}
            </span>
          </button>
        </div>
      </div>
    </div>
  );
}

Finder__FiltersMobile.propTypes = {
  config: PropTypes.object,
  query: PropTypes.object,
  response: PropTypes.object,
  update: PropTypes.object,
  clear: PropTypes.func,
  updating: PropTypes.bool,
  summariseAs: PropTypes.object,
  mobile: PropTypes.bool,
  hasMounted: PropTypes.bool,
  matrixState: PropTypes.bool,
};

export default Finder__FiltersMobile;
