import { useState, useEffect, useRef } from "react";
import useHasMounted from "./has-mounted";
import replaceHistory from "./replace-history";
import { getNonFBParams, getFacetParams } from "./url-params";
import { reduceMotion } from "../util";
import { find } from './funnelback';
import scroll from "zenscroll";

import type { MatrixConfigJSON } from "../types/configJSON";
import type { Response } from "../types/FBresponse";
import type { QueryDetails } from "../types/query";

type Cancelable = { cancel: () => void };

function useLogicWrapper(
  config: MatrixConfigJSON,
  results: Response,
  matrixQuery: URLSearchParams | { [key: string]: string | string[] },
  element: HTMLElement | null,
) {
  const summaryHeadingRef = useRef<HTMLDivElement | null>(null);
  const hasMounted = useHasMounted();
  const screenOffsetRatio = 10;

  const scrollDuration =
    typeof window !== "undefined" && !reduceMotion() ? 1000 : 0;

  const initialResults = results || {};
  const nonFBParams =
    config.facetLabels && config.facetLabels.filter((p) => p.nonFBParam);
  const initializeParams =
    config.facetLabels && config.facetLabels.length > 0
      ? getFacetParams(config.facetLabels, matrixQuery)
      : {};
  const site = config.site || undefined;
  const profile = config.profile || "_default";

  /**
   * initial state for the Funnelback query, taken from URL parameters and
   * configuration
   **/
  // Normalize matrixQuery access for both URLSearchParams and plain objects
  const isURLSearchParams =
    typeof URLSearchParams !== "undefined" && matrixQuery instanceof URLSearchParams;

  const matrixQueryGet = (key: string): string | null => {
    if (!matrixQuery) return null;
    if (isURLSearchParams) {
      return (matrixQuery as URLSearchParams).get(key);
    }
    const mq = matrixQuery as { [key: string]: string | string[] };
    const val = mq[key];
    if (Array.isArray(val)) return val[0] || null;
    return (typeof val === "string" ? val : null);
  };

  const matrixQueryGetRaw = (key: string): string | string[] | undefined => {
    if (!matrixQuery) return undefined;
    if (isURLSearchParams) {
      // URLSearchParams doesn't expose arrays; return single value
      const v = (matrixQuery as URLSearchParams).get(key);
      return v === null ? undefined : v;
    }
    return (matrixQuery as { [key: string]: string | string[] })[key];
  };

  const initialQuery = {
    collection: config.collection,
    profile: profile,
    facets: initializeParams,
    parameters: nonFBParams && nonFBParams.length > 0 && matrixQuery
                ? getNonFBParams(config.facetLabels || [], matrixQuery)
                : {},
    fixedFacets: config.fixedFacets,
    fixedParameters: config.fixParameters ? config.fixParameters : [],
    interacted: false,
    misspelling: null as string | null,
    numRanks: config.numRanks,
    query: matrixQuery && matrixQueryGet("query")
      ? matrixQueryGet("query") || ""
      : "",
    sortType: config.sort[0].type,
    startRank: (() => {
      const raw = matrixQueryGetRaw("start_rank");
      if (!raw) return 1;
      if (Array.isArray(raw)) return parseInt(raw[0], 10) || 1;
      return parseInt(raw, 10) || 1;
    })(),
    testinitializeParams: initializeParams,
  };

const [defaultParams, setDefaultParams] = useState<URLSearchParams | null>(null);
  const [query, setQuery] = useState<QueryDetails>(initialQuery); // will set once defaultParams is ready
  const [funnelbackResponse, setResponse] = useState<Readonly<Response>>(
    Object.keys(initialResults).length > 0
      ? Object.freeze(results)
      : Object.freeze({
          bestBets: [],
          extraSearches: {},
          facets: [],
          results: [],
          spell: null,
          summary: {
            currEnd: 0,
            currStart: 0,
            numRanks: 0,
            totalMatching: 0,
          },
        }),
  );

  const [updating, setUpdating] = useState(
    Object.keys(initialResults).length === 0,
  );
  const [call, setCall] = useState<Cancelable>({ cancel: () => {} });
  const [update, setUpdate] = useState(false);

  // Step 1: Initialize defaultParams after mount
  useEffect(() => {
  if (!defaultParams && typeof window !== "undefined") {
    const searchParams = new URLSearchParams(window.location.search);

    // merge in matrixQuery (SSR params)
    if (matrixQuery) {
      if (typeof URLSearchParams !== "undefined" && matrixQuery instanceof URLSearchParams) {
        for (const [key, value] of matrixQuery.entries()) {
          searchParams.append(key, value);
        }
      } else {
        Object.entries(matrixQuery as { [key: string]: string | string[] }).forEach(([key, value]) => {
          if (Array.isArray(value)) {
            value.forEach((v) => searchParams.append(key, v));
          } else {
            searchParams.append(key, value as string);
          }
        });
      }
    }

    setDefaultParams(searchParams);
  }
}, [defaultParams, matrixQuery]);

  // Step 2: Build initial query once defaultParams is ready
// Step 2: Build initial query once defaultParams is ready
useEffect(() => {
  if (!defaultParams) return;

  const matrixState = !hasMounted && matrixQuery ? true : false;

  const baseQuery = {
    collection: config.collection,
    facets:
      config.facetLabels && config.facetLabels.length > 0
        ? getFacetParams(config.facetLabels, defaultParams)
        : {},
    parameters:
      config.facetLabels && nonFBParams && nonFBParams.length > 0
        ? getNonFBParams(config.facetLabels, defaultParams)
        : {},
    fixedFacets: config.fixedFacets,
    fixedParameters: config.fixParameters || [],
    interacted: false,
    misspelling: null as string | null,
    numRanks: config.numRanks,
    query:
      !matrixState && defaultParams.get("query")
        ? defaultParams.get("query")!
        : defaultParams.get("query") || "",
    sortType:
      !matrixState && defaultParams.get("query")
        ? ""
        : !matrixState && defaultParams.get("sort")
          ? defaultParams.get("sort")!
          : config.sort[0].type,
    startRank:
      !matrixState && defaultParams.get("start_rank")
        ? parseInt(defaultParams.get("start_rank")!, 10)
        : defaultParams.get("start_rank")
          ? parseInt(defaultParams.get("start_rank")!, 10)
          : 1,
  };

  setQuery(baseQuery);
}, [defaultParams, hasMounted]);


  // Step 3: Patch query after mount
  useEffect(() => {
    if (!hasMounted || !defaultParams) return;

    const numRanksParam = defaultParams.get("num_ranks");
    if (!numRanksParam) return;

    setQuery((prev) => ({
      ...prev,
      numRanks: parseInt(numRanksParam, 10) || prev.numRanks,
    }));
  }, [hasMounted, defaultParams]);

  // Step 4: Update response when `update` flips
  useEffect(() => {
    if (!query) return;
    replaceHistory(
      query.query,
      query.startRank,
      query.facets,
      query.parameters || {},
      query.sortType,
      config.facetLabels || [],
      config.sort[0].type,
      hasMounted,
    );

    setUpdating(true);

    if (query.interacted && element) {
      const resultsEl = element.querySelector(".finder__results");
      if (resultsEl instanceof HTMLElement) {
        scroll.center(
          resultsEl,
          scrollDuration,
          -window.innerHeight / screenOffsetRatio,
        );
      }
    }

    call.cancel();

    const [request, requestToken] = find(
      query.collection,
      query.fixedFacets,
      query.fixedParameters,
      query.query,
      query.sortType,
      query.startRank,
      query.numRanks,
      query.facets,
      query.parameters,
      site,
      config.facetLabels,
      profile,
    );

    setCall({ cancel: () => requestToken.cancel() });

    request
      .then((data) => {
        setResponse(data as Readonly<Response>); // ✅ Freeze before setting
        setUpdating(false);
      })
      .then(() => {
        if (query.interacted && summaryHeadingRef.current) {
          summaryHeadingRef.current.scrollIntoView({
            behavior: "smooth",
            block: "nearest",
            inline: "center",
          });
        }
      })
      .catch(() => {
        setResponse(initialResults as Readonly<Response>);
        setUpdating(false);
      });
  }, [update, query]);

  const updater = {
    query: (newQuery: QueryDetails) => setQuery(newQuery),
    results: (newUpdate: boolean) => setUpdate(newUpdate),
    updateState: update,
  };

  const clear = (resetSort?: boolean) => {
    const newQuery = {
      ...query,
      sortType: resetSort ? config.sort[0].type : query.sortType,
      facets: {},
      parameters: {},
      startRank: 1,
      misspelling: null as string | null,
      interacted: true,
    };
    call.cancel();
    setQuery(newQuery);
    setUpdate(!update);
  };

  return {
    query,
    funnelbackResponse,
    updating,
    updater,
    clear,
    hasMounted,
    matrixState: !hasMounted && matrixQuery ? true : false,
    summaryHeadingRef,
  };
}

export default useLogicWrapper;
