import React from "react";
import PropTypes from "prop-types";
import ClearFilterTag from "../filters/finder__clearFilterTag";
import Reset from "../filters/finder__reset";
import type { ClearFilters } from "../../types/results/results";


function ClearFilters(props: ClearFilters) {
    const {query, clear, update, config, updating} = props;

    const clearFiltersDesktop =
          !updating && Object.keys(props.query.facets).length > 0 ? (
            <div className="v26-finder__filters__reset v26-finder__filters__reset--desktop">
              <Reset
                clear={props.clear}
                resetSort={false}
                matrixState={props.matrixState}
                site={props.config.site || "city"} // Ensure site is defined
              />
            </div>
          ) : null;
    
    return (
        <div className="v26-finder__results__clear-filters">
            {
                config.facetLabels?.map((facet) => {
                    if (query.facets && query.facets[facet.meta]) {
                        if (Array.isArray(query.facets[facet.meta])) {
                            // Return the mapped array so React will render the tags
                            return (query.facets[facet.meta] as string[]).map((facetValue: string) => {
                                return (
                                    <ClearFilterTag
                                        key={`${facet.meta}-${facetValue}`}
                                        value={facetValue}
                                        facet={facet}
                                        query={query}
                                        update={update}
                                        clear={clear}
                                        dependencies={config.facetLabels &&
                                                        config.facetLabels.filter(
                                                            (candidate) => candidate.dependency === facet.meta,
                                                        )}
                                    />
                                );
                            });
                        } else {
                            return (
                                <ClearFilterTag
                                    key={`${facet.meta}-${query.facets[facet.meta] as string}`}
                                    value={query.facets[facet.meta] as string}
                                    facet={facet}
                                    query={query}
                                    update={update}
                                    clear={clear}
                                    dependencies={config.facetLabels &&
                                                    config.facetLabels.filter(
                                                        (candidate) => candidate.dependency === facet.meta,
                                                    )}
                                />
                            );
                        }
                    }
                    return null;
                })
            }
            {clearFiltersDesktop}
        </div>
    );
}

ClearFilters.propTypes = {
  query: PropTypes.object,
  update: PropTypes.object,
  clear: PropTypes.func,
  config: PropTypes.object,
  matrixState: PropTypes.bool,
  updating: PropTypes.bool
};

export default ClearFilters;
