import React from "react";
import PropTypes from "prop-types";
import Query from "../../components/query/finder__query";
import DefaultFilters from "../../components/filters/finder__filtersmobile";
import CityFilters from "../../components/filters/city/finder__filtersmobile-city";
import CitySportsFilters from "../../components/filters/city-sport/finder__filtersmobile-citySports";
import Results from "../../components/results/finder__results";
import useLogicWrapper from "../../logic/logic";
import useHasMounted from "../../logic/has-mounted";

import type { MatrixConfigJSON } from "../../types/configJSON";
import type { Response } from "../../types/FBresponse";

type FinderProps = {
  config: MatrixConfigJSON;
  initialResults?: Response;
  initialQuery?: {[key: string]: string | string[]};
  element: HTMLElement | null;
};

function Finder(props: FinderProps) {
  const hasMounted = useHasMounted();
  const intialResults = Object.freeze({
          bestBets: [],
          extraSearches: {},
          facets: [],
          results: [],
          spell: null,
          summary: {
            currEnd: 0,
            currStart: 0,
            numRanks: 0,
            totalMatching: 0,
          },
        });
  const initialQuery = hasMounted ? new URLSearchParams(window.location.search) : props.initialQuery || {};
  const {
    query,
    funnelbackResponse,
    updating,
    updater,
    clear,
    matrixState,
    summaryHeadingRef,
  } = useLogicWrapper(
    props.config,
    props.initialResults ?? intialResults,
    initialQuery,
    props.element,
  );
  //props.initialQuery || {}, need to find a way to pass the initial query from the URL parameters in the server rendering, as currently it is not being passed and is defaulting to an empty object, which causes issues with the initial render of the component as it is expecting certain parameters to be present in the query object. This is likely due to the fact that the initial query is being parsed from the URL parameters in the server rendering, but is not being passed down to the Finder component as a prop, which is causing it to default to an empty object. This needs to be fixed in order for the Finder component to render correctly on the initial load.
  
  const sharedProps = {
  config: props.config,
  query,
  response: funnelbackResponse,
  update: updater,
  updating,
  summariseAs: props.config.summariseAs,
  clear,
  mobile: true,
  hasMounted,
  matrixState,
};

  
  console.log('props.config.site:', props.config.site);
  const finderMain = (
    <>
      {props.config.facetLabels && props.config.facetLabels.length > 0 && (
        props.config.site === "city" ? (
          <CityFilters {...sharedProps} />
        ) : props.config.site === "citysport" ? (
          <CitySportsFilters {...sharedProps} />
        ) : (
          <DefaultFilters {...sharedProps} />
        )
      )}

      <Results
        clear={clear}
        config={props.config}
        query={query}
        response={funnelbackResponse}
        summariseAs={props.config.summariseAs}
        type={props.config.resultCard}
        update={updater}
        updating={updating}
        summaryHeadingRef={summaryHeadingRef}
        matrixState={matrixState}
      />
    </>
  );

  const QueryInput = (
    <Query
      config={props.config}
      query={query}
      update={updater}
      updating={updating}
    />
  );

  // If the site is bayes, we want to render the query input in the top section

  const topSectionQueryInput =
    props.config.queryInputConfig &&
    props.config.queryInputConfig.showQueryInTopSection ? (
      <div className="v26-finder__top">
        <div className="container">{QueryInput}</div>
      </div>
    ) : null;

  return (
    <form
      className="v26-finder"
      method="GET"
      onSubmit={(e) => {
        e.preventDefault();
      }}
    >
      {props.config.site && props.config.site === "bayes" ? (
        <>
          {topSectionQueryInput}
          <div className="v26-finder__main">
            <div className="container">
              <div className="grid">{finderMain}</div>
            </div>
          </div>
        </>
      ) : (
        <>
          {QueryInput}
          {finderMain}
        </>
      )}
    </form>
  );
}

Finder.propTypes = {
  config: PropTypes.object.isRequired,
  element: PropTypes.object,
  initialQuery: PropTypes.object,
  initialResults: PropTypes.object,
};

export default Finder;
